  const files = fs.readdirSync(siteDataDir).filter((f) => f.endsWith(".json"));
  let valid = 0;
  let invalid = 0;
  for (const f of files) {
    try {
      JSON.parse(fs.readFileSync(path.join(siteDataDir, f), "utf8"));
      valid++;
    } catch (err) {
