    } catch (err) {
      console.warn(`  [site-data] INVALID JSON: ${f} — ${err.message}`);
      invalid++;
    }
  }
  console.log(`  [site-data] validated ${valid} file(s)${invalid ? `, ${invalid} INVALID` : ""}`);
}

